using Ledgerly.Application.Abstractions; using Ledgerly.Domain.Entities; using Microsoft.EntityFrameworkCore; namespace Ledgerly.Infrastructure.Persistence.Repositories; public sealed class BillRepository:IBillRepository{ private readonly LedgerlyDbContext _context; public BillRepository(LedgerlyDbContext context)=>_context=context; public Task<Bill?> GetByIdAsync(Guid organizationId,Guid billId,CancellationToken cancellationToken=default)=>_context.Bills.Include(b=>b.Lines).FirstOrDefaultAsync(b=>b.OrganizationId==organizationId&&b.Id==billId,cancellationToken); public async Task AddAsync(Bill bill,CancellationToken cancellationToken=default){await _context.Bills.AddAsync(bill,cancellationToken);await _context.SaveChangesAsync(cancellationToken);} public async Task UpdateAsync(Bill bill,CancellationToken cancellationToken=default){_context.Bills.Update(bill);await _context.SaveChangesAsync(cancellationToken);} } public sealed class ExpenseRepository:IExpenseRepository{ private readonly LedgerlyDbContext _context; public ExpenseRepository(LedgerlyDbContext context)=>_context=context; public Task<Expense?> GetByIdAsync(Guid organizationId,Guid expenseId,CancellationToken cancellationToken=default)=>_context.Expenses.FirstOrDefaultAsync(e=>e.OrganizationId==organizationId&&e.Id==expenseId,cancellationToken); public async Task AddAsync(Expense expense,CancellationToken cancellationToken=default){await _context.Expenses.AddAsync(expense,cancellationToken);await _context.SaveChangesAsync(cancellationToken);} public async Task UpdateAsync(Expense expense,CancellationToken cancellationToken=default){_context.Expenses.Update(expense);await _context.SaveChangesAsync(cancellationToken);} }
